"use client"

import { useState } from "react"

export default function Checkout({price}){

const [loading,setLoading] = useState(false)

const handleCheckout = async () => {

  setLoading(true)

  const res = await fetch("/api/create-preference",{
    method:"POST",
    headers:{
      "Content-Type":"application/json"
    },
    body:JSON.stringify({
      title:"Compra tienda",
      price:price
    })
  })

  const data = await res.json()

  window.location.href =
  `https://www.mercadopago.com.ar/checkout/v1/redirect?pref_id=${data.id}`

}

return(

<button
onClick={handleCheckout}
disabled={loading}
style={{
padding:"12px 20px",
background:"#009ee3",
color:"white",
border:"none",
borderRadius:"8px",
cursor:"pointer"
}}
>

{loading ? "Redirigiendo..." : "Pagar con MercadoPago"}

</button>

)

}